async (page) => {
  const result = await page.evaluate(() => {
    const g = window.game;

    // Get player.follow implementation
    const followFn = g.player.follow?.toString().substring(0, 600);

    // Look at player.pursue (NPC follow)
    const pursueFn = g.player.pursue?.toString().substring(0, 300);

    // Check what socket packets are available
    // Look for Packets constants
    let packetsStr = '';
    try {
      // Try to find the Packets enum
      const possiblePackets = [];
      for (let key in window) {
        if (key.toLowerCase() === 'packets' || key.toLowerCase() === 'packet') {
          possiblePackets.push(key + ': ' + JSON.stringify(window[key]).substring(0, 200));
        }
      }
      packetsStr = possiblePackets.join(', ');
    } catch(e) {}

    // Check socket send calls
    const socketSend = g.socket.send?.toString().substring(0, 200);

    return JSON.stringify({ followFn, pursueFn, socketSend, packetsStr: packetsStr.substring(0, 200) });
  });
  return result.substring(0, 2000);
}

