async (page) => {
  for (let attempt = 0; attempt < 12; attempt++) {
    const oaks = await page.evaluate(() => {
      const g = window.game;
      const entities = Object.values(g.entities.entities);
      const camera = g.camera;
      const ts = g.map.tileSize;
      const zf = camera.zoomFactor;
      return entities
        .filter(e => e.name === 'Oak')
        .map(e => ({
          gridX: e.gridX, gridY: e.gridY, instance: e.instance,
          dist: Math.abs(e.gridX - g.player.gridX) + Math.abs(e.gridY - g.player.gridY),
          sx: Math.round((e.gridX * ts + ts/2 - camera.x) * zf),
          sy: Math.round((e.gridY * ts + ts/2 - camera.y) * zf)
        }))
        .sort((a, b) => a.dist - b.dist)
        .slice(0, 5);
    });

    const logs = await page.evaluate(() =>
      window.__latestGameState?.inventory?.filter(i => i.key === 'logs')?.reduce((a, i) => a + i.count, 0) || 0
    );
    if (logs >= 10) break;

    // Find one that's on screen
    const target = oaks.find(o => o.sx > 100 && o.sx < 1180 && o.sy > 50 && o.sy < 680);
    if (target) {
      await page.evaluate(({sx, sy}) => {
        document.getElementById('canvas').dispatchEvent(
          new MouseEvent('click', { clientX: sx, clientY: sy, bubbles: true, ctrlKey: false })
        );
      }, target);
      await page.waitForTimeout(5000);
    } else {
      // Walk to nearest oak
      if (oaks.length > 0) {
        const o = oaks[0];
        const clampedX = Math.max(200, Math.min(1080, o.sx));
        const clampedY = Math.max(100, Math.min(650, o.sy));
        await page.evaluate(({x, y}) => {
          document.getElementById('canvas').dispatchEvent(
            new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false })
          );
        }, { x: clampedX, y: clampedY });
        await page.waitForTimeout(4000);
      } else {
        await page.waitForTimeout(5000); // wait for respawn
      }
    }
  }

  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });

  return await page.evaluate(() => {
    const gs = window.__latestGameState;
    const g = window.game;
    return JSON.stringify({
      logs: gs?.inventory?.filter(i => i.key === 'logs')?.reduce((a, i) => a + i.count, 0) || 0,
      inventory: gs?.inventory?.map(i => `${i.name}x${i.count}`),
      questStage: gs?.quests?.find(q => q.key === 'foresting')?.stage,
      pos: { x: g.player.gridX, y: g.player.gridY }
    });
  });
}

