async (page) => {
  // Reset monitoring
  await page.evaluate(() => {
    window.__npcCallbackFired = false;
    window.__npcMessages = [];
    window.__questCallbackFired = false;
    window.__questCallbackArgs = null;
    window.__questPanelShown = false;
  });

  // Compute Forester screen coords from current camera
  const foresterCoords = await page.evaluate(() => {
    const g = window.game;
    const entities = Object.values(g.entities.entities);
    const forester = entities.find(e => e.name === 'Forester');
    if (!forester) return null;
    const camera = g.camera;
    const ts = g.map.tileSize;
    const zf = camera.zoomFactor;
    return {
      sx: Math.round((forester.gridX * ts + ts/2 - camera.x) * zf),
      sy: Math.round((forester.gridY * ts + ts/2 - camera.y) * zf),
      dist: Math.abs(forester.gridX - g.player.gridX) + Math.abs(forester.gridY - g.player.gridY)
    };
  });

  // Walk to Forester (may take multiple clicks if far away)
  for (let step = 0; step < 4; step++) {
    const coords = await page.evaluate(() => {
      const g = window.game;
      const entities = Object.values(g.entities.entities);
      const forester = entities.find(e => e.name === 'Forester');
      if (!forester) return null;
      const camera = g.camera;
      const ts = g.map.tileSize;
      const zf = camera.zoomFactor;
      const sx = Math.round((forester.gridX * ts + ts/2 - camera.x) * zf);
      const sy = Math.round((forester.gridY * ts + ts/2 - camera.y) * zf);
      const dist = Math.abs(forester.gridX - g.player.gridX) + Math.abs(forester.gridY - g.player.gridY);
      return { sx, sy, dist };
    });

    if (!coords || coords.dist <= 2) break;

    // Click toward Forester
    const clampX = Math.max(150, Math.min(1130, coords.sx));
    const clampY = Math.max(80, Math.min(640, coords.sy));
    await page.evaluate(({x, y}) => {
      document.getElementById('canvas').dispatchEvent(
        new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false })
      );
    }, { x: clampX, y: clampY });
    await page.waitForTimeout(4000);

    if (window.__npcCallbackFired) break;
  }

  await page.waitForTimeout(2000);

  // Check if NPC fired
  const state = await page.evaluate(() => ({
    npcFired: window.__npcCallbackFired,
    npcMessages: window.__npcMessages,
    playerPos: { x: window.game.player.gridX, y: window.game.player.gridY }
  }));

  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  return JSON.stringify({ foresterCoords, state });
}

async (page) => {
  const info = await page.evaluate(() => {
    const g = window.game;
    const player = g.player;

    // Check skills directly from player object
    const skills = {};
    if (player.skills) {
      for (const [k, v] of Object.entries(player.skills)) {
        skills[k] = { level: v?.level, experience: v?.experience };
      }
    }

    // Check equipment
    const equipment = {};
    if (player.equipment) {
      for (const [k, v] of Object.entries(player.equipment)) {
        if (v?.name) equipment[k] = v.name;
      }
    }

    return { skills, equipment, level: player.level };
  });
  return JSON.stringify(info);
}

