      const zf = camera.zoomFactor;
      const px = g.player.gridX, py = g.player.gridY;

      return entities
        .filter(e => e.isMob?.())
        .map(e => ({
          name: e.name,
          dist: Math.abs(e.gridX - px) + Math.abs(e.gridY - py),
          sx: Math.round((e.gridX * ts + ts/2 - camera.x) * zf),
          sy: Math.round((e.gridY * ts + ts/2 - camera.y) * zf)
        }))
        .filter(m => m.sx > 50 && m.sx < 1230 && m.sy > 30 && m.sy < 690)
        .sort((a, b) => a.dist - b.dist)[0] || null;
    });

    if (mob) {
      await page.evaluate(({sx, sy}) => {
        document.getElementById('canvas').dispatchEvent(
          new MouseEvent('click', { clientX: sx, clientY: sy, bubbles: true, ctrlKey: false })
