    } else {
      await page.evaluate(() => {
        document.getElementById('canvas').dispatchEvent(
          new MouseEvent('click', { clientX: 400 + Math.random()*480, clientY: 200 + Math.random()*300, bubbles: true, ctrlKey: false })
