      const g = window.game;
      const camera = g.camera;
      const ts = g.map.tileSize;
      const zf = camera.zoomFactor;
      const px = g.player.gridX, py = g.player.gridY;

      // Check if Blacksmith is in entity list
      const entities = Object.values(g.entities.entities);
      const blacksmith = entities.find(e => e.name === 'Blacksmith');

      let bsCoords = null;
      if (blacksmith) {
        bsCoords = {
          sx: Math.round((blacksmith.gridX * ts + ts/2 - camera.x) * zf),
          sy: Math.round((blacksmith.gridY * ts + ts/2 - camera.y) * zf),
          dist: Math.abs(blacksmith.gridX - px) + Math.abs(blacksmith.gridY - py)
        };
      }

      // Target coords (199, 169)
      const targetSx = Math.round((199 * ts + ts/2 - camera.x) * zf);
      const targetSy = Math.round((169 * ts + ts/2 - camera.y) * zf);

      return { px, py, bsCoords, targetSx, targetSy };
    });

    if (posInfo.bsCoords && posInfo.bsCoords.dist <= 2) break;

    // Click toward Blacksmith (either on entity or on target tile)
    const targetX = posInfo.bsCoords ? 
      Math.max(150, Math.min(1130, posInfo.bsCoords.sx)) :
      Math.max(150, Math.min(1130, posInfo.targetSx));
    const targetY = posInfo.bsCoords ?
      Math.max(80, Math.min(640, posInfo.bsCoords.sy)) :
      Math.max(80, Math.min(640, posInfo.targetSy));

