      document.getElementById('canvas').dispatchEvent(
        new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false })
      );
    }, { x: targetX, y: targetY });
    await page.waitForTimeout(4000);

    if (window.__npcCallbackFired) break;
